import * as React from "react"
import { X } from "lucide-react"

import { cn } from "@/lib/utils"
import "./callout-card.css"

function CalloutCard({
  className,
  icon,
  title,
  description,
  action,
  onDismiss,
  ...props
}: React.ComponentProps<"div"> & {
  icon?: React.ReactNode
  title?: string
  description?: string
  action?: React.ReactNode
  onDismiss?: () => void
}) {
  return (
    <div
      data-slot="callout-card"
      className={cn("callout-card-base", className)}
      {...props}
    >
      <div className="flex flex-col gap-[var(--layout-gap-sm)] w-full">
        {(icon || title || onDismiss) && (
          <div className="flex items-start justify-between w-full">
            <div className="flex gap-[var(--layout-gap-sm)] items-center">
              {icon && (
                <span
                  className="callout-card-icon shrink-0"
                  aria-hidden="true"
                >
                  {icon}
                </span>
              )}
              {title && (
                <p className="callout-card-title text-content-note font-accent">
                  {title}
                </p>
              )}
            </div>
            {onDismiss && (
              <button
                type="button"
                onClick={onDismiss}
                className="callout-card-dismiss shrink-0 cursor-pointer inline-flex items-center justify-center size-[var(--layout-size-xs)]"
                aria-label="Dismiss"
              >
                <X className="size-[var(--layout-size-2xs)]" />
              </button>
            )}
          </div>
        )}
        {description && (
          <p className="callout-card-description text-content-note">
            {description}
          </p>
        )}
      </div>
      {action && <div className="w-full">{action}</div>}
    </div>
  )
}

export { CalloutCard }

/* ================================================================
 * CALLOUT CARD — Styles
 * Structure (flex, gap) lives in callout-card.tsx.
 * Theming (colors, borders) lives here via tokens.
 * ================================================================ */

/* --------------------------------
 * Base
 * -------------------------------- */
.callout-card-base {
  display: flex;
  flex-direction: column;
  gap: var(--layout-gap-lg);
  align-items: flex-start;
  justify-content: center;
  background: var(--background-neutral-lighter-default);
  border: var(--layout-border-thin) solid var(--border-default);
  border-radius: var(--layout-radius-2xl);
  padding: var(--layout-padding-lg);
}

/* --------------------------------
 * Icon
 * -------------------------------- */
.callout-card-icon {
  color: var(--icon-brand-moderate);
}

.callout-card-icon > svg {
  width: var(--layout-size-xs);
  height: var(--layout-size-xs);
}

/* --------------------------------
 * Title
 * -------------------------------- */
.callout-card-title {
  color: var(--text-brand-moderate);
}

/* --------------------------------
 * Dismiss
 * -------------------------------- */
.callout-card-dismiss {
  color: var(--icon-neutral-moderate);
}

@media (prefers-reduced-motion: no-preference) {
  .callout-card-dismiss {
    transition: color 150ms ease;
  }
}

.callout-card-dismiss:hover {
  color: var(--text-base-strong);
}

/* --------------------------------
 * Description
 * -------------------------------- */
.callout-card-description {
  color: var(--text-base-moderate);
}
